<?php
namespace App\Http\Controllers\Api;
use App\Actions\{CreateServiceEntryAction,UpdateServiceEntryAction};use App\Http\Requests\ServiceEntryRequest;use App\Models\{Project,ServiceEntry};use App\Http\Controllers\Controller;
class ServiceEntryController extends Controller{public function index(Project $project){$this->authorize('view',$project);return $project->serviceEntries()->with('contractor','tags')->latest('date')->get();} public function store(ServiceEntryRequest $r,Project $project,CreateServiceEntryAction $a){$this->authorize('update',$project);return $a->execute($r->validated()+['project_id'=>$project->id]);} public function show(ServiceEntry $serviceEntry){$this->authorize('view',$serviceEntry);return $serviceEntry->load('contractor','tags');} public function update(ServiceEntryRequest $r,ServiceEntry $serviceEntry,UpdateServiceEntryAction $a){$this->authorize('update',$serviceEntry);return $a->executeUpdate($serviceEntry,$r->validated());} public function destroy(ServiceEntry $serviceEntry){$this->authorize('delete',$serviceEntry);$serviceEntry->delete();return response()->noContent();}}
